using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;

/// <summary>
/// Menu Secundário ("-", Tarefa #35): abre com o botão "-"
/// (<see cref="PlayerInputRouter.SecondaryMenuPressed"/>) e contém as secções
/// principais do jogo — Área Atual, Diário, Formas, Itens &amp; Instintos,
/// Progresso, Upgrades, Emblemas.
///
/// O Menu de Pausa ("+" — <see cref="PauseMenuController"/>) fica apenas com
/// <see cref="OptionsSectionUI"/>, tornando-se um atalho directo para Opções.
///
/// Aceita tanto <see cref="ISecondaryMenuTab"/> como <see cref="IPauseMenuSection"/>
/// em "tabBehaviours" — as secções existentes (<c>AreaSectionUI</c>,
/// <c>DiarySectionUI</c>, etc.) implementam <c>IPauseMenuSection</c> e são
/// adaptadas internamente sem precisar de ser alteradas.
///
/// - Abre/fecha com "-". Se o Menu de Pausa estiver aberto, não abre.
/// - Navega com L/R (PrevFormTapped/NextFormTapped).
/// - "B"/Escape fecha.
/// - Animação idêntica ao Menu de Pausa (escala+fade, ~0.25-0.35s).
///
/// Montagem no Editor:
/// - "panelRoot"/"canvasGroup"/"animatedRoot": painel e animação.
/// - "tabLabels": um TMP_Text por aba, na MESMA ordem que "tabBehaviours".
/// - "tabBehaviours": MonoBehaviours que implementam ISecondaryMenuTab OU
///   IPauseMenuSection (ex: AreaSectionUI, DiarySectionUI, FormsSectionUI,
///   ItemsInstinctsSectionUI, ProgressSectionUI, UpgradesTabUI, EmblemsSectionUI).
/// </summary>
public class SecondaryMenuController : MonoBehaviour
{
    public static SecondaryMenuController Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private RectTransform animatedRoot;

    [Header("Animação de Abertura/Fecho")]
    [Tooltip("Duração da animação de abrir/fechar (GDD: 0.25 a 0.35s).")]
    [SerializeField] private float animDuration = 0.3f;

    [Tooltip("Escala inicial (ao abrir) / final (ao fechar).")]
    [SerializeField] private float closedScale = 0.85f;

    [Header("Navegação de Abas")]
    [Tooltip("Um TMP_Text por aba (mesma ordem que 'tabBehaviours'), para realçar a aba actual.")]
    [SerializeField] private List<TMP_Text> tabLabels = new List<TMP_Text>();
    [SerializeField] private Color tabInactiveColor = new Color(1f, 1f, 1f, 0.5f);
    [SerializeField] private Color tabActiveColor = Color.white;

    [Header("Abas (ordem: Upgrades, ...)")]
    [Tooltip("Cada elemento deve implementar ISecondaryMenuTab.")]
    [SerializeField] private List<MonoBehaviour> tabBehaviours = new List<MonoBehaviour>();

    [Header("Som")]
    [SerializeField] private AudioClip openSfx;
    [SerializeField] private AudioClip closeSfx;
    [SerializeField] private AudioClip tabChangeSfx;

    [Header("Referências")]
    [SerializeField] private PlayerInputRouter input;

    private readonly List<ISecondaryMenuTab> tabs = new List<ISecondaryMenuTab>();
    private int currentTabIndex;
    private bool isOpen;
    private Coroutine animRoutine;

    public bool IsOpen => isOpen;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;

        tabs.Clear();
        foreach (var mb in tabBehaviours)
        {
            ISecondaryMenuTab tab = null;

            if (mb is ISecondaryMenuTab directTab)
                tab = directTab;
            else if (mb is IPauseMenuSection section)
                tab = new PauseSectionAdapter(section);

            if (tab != null)
            {
                tabs.Add(tab);
                if (tab.Root != null) tab.Root.SetActive(false);
            }
            else
            {
                Debug.LogError($"[SecondaryMenuController] '{(mb != null ? mb.name : "null")}' não implementa ISecondaryMenuTab nem IPauseMenuSection — ignorado.");
            }
        }

        if (panelRoot != null) panelRoot.SetActive(false);
        if (canvasGroup != null) canvasGroup.alpha = 0f;
    }

    private void Start()
    {
        if (input == null) input = FindObjectOfType<PlayerInputRouter>();
    }

    private void OnEnable()
    {
        if (input == null) input = FindObjectOfType<PlayerInputRouter>();
        if (input == null) return;

        input.SecondaryMenuPressed += OnSecondaryMenuPressed;
        input.PrevFormTapped += OnPrevTab;
        input.NextFormTapped += OnNextTab;
    }

    private void OnDisable()
    {
        if (input == null) return;

        input.SecondaryMenuPressed -= OnSecondaryMenuPressed;
        input.PrevFormTapped -= OnPrevTab;
        input.NextFormTapped -= OnNextTab;
    }

    // ---------------- Abrir / Fechar ----------------

    private void OnSecondaryMenuPressed()
    {
        // Não abre se o Menu de Pausa estiver aberto (e fecha se já estiver aberto).
        if (PauseMenuController.Instance != null && PauseMenuController.Instance.IsOpen) return;

        if (isOpen) Close();
        else Open();
    }

    public void Open()
    {
        if (isOpen) return;
        if (tabs.Count == 0)
        {
            Debug.LogWarning("[SecondaryMenuController] Nenhuma aba configurada — menu não abre.");
            return;
        }

        isOpen = true;

        GamePauseUtil.Pause();
        AudioManager.Instance?.SetBgmMuffled(true);

        if (panelRoot != null) panelRoot.SetActive(true);

        ShowTab(currentTabIndex, refresh: true);

        PlayAnimation(opening: true);
        AudioManager.Instance?.PlaySE(openSfx);
    }

    public void Close()
    {
        if (!isOpen) return;

        isOpen = false;

        if (currentTabIndex < tabs.Count)
            tabs[currentTabIndex].OnHide();

        if (EventSystem.current != null) EventSystem.current.SetSelectedGameObject(null);

        PlayAnimation(opening: false);
        AudioManager.Instance?.PlaySE(closeSfx);
    }

    // ---------------- Navegação de Abas ----------------

    private void OnPrevTab()
    {
        if (!isOpen) return;
        ChangeTab(-1);
    }

    private void OnNextTab()
    {
        if (!isOpen) return;
        ChangeTab(1);
    }

    private void ChangeTab(int delta)
    {
        if (tabs.Count <= 1) return;

        int next = (currentTabIndex + delta + tabs.Count) % tabs.Count;
        if (next == currentTabIndex) return;

        tabs[currentTabIndex].OnHide();
        ShowTab(next, refresh: true);

        AudioManager.Instance?.PlaySE(tabChangeSfx);
    }

    private void ShowTab(int index, bool refresh)
    {
        currentTabIndex = index;

        for (int i = 0; i < tabs.Count; i++)
        {
            bool active = i == index;

            if (tabs[i].Root != null) tabs[i].Root.SetActive(active);

            if (i < tabLabels.Count && tabLabels[i] != null)
                tabLabels[i].color = active ? tabActiveColor : tabInactiveColor;
        }

        if (refresh) tabs[index].Refresh();
    }

    // ---------------- Utilitário ----------------

    /// <summary>
    /// Abre o menu directamente numa aba específica — ex: chamado por um
    /// sistema externo para revelar um upgrade recém-desbloqueado.
    /// </summary>
    public void OpenToTab(MonoBehaviour tabBehaviour)
    {
        int index = tabBehaviours.IndexOf(tabBehaviour);
        if (index < 0)
        {
            Open();
            return;
        }

        bool wasOpen = isOpen;
        if (!wasOpen) Open();

        if (index != currentTabIndex)
        {
            tabs[currentTabIndex].OnHide();
            ShowTab(index, refresh: true);
            if (wasOpen) AudioManager.Instance?.PlaySE(tabChangeSfx);
        }
    }

    /// <summary>Toca um som orgânico através do AudioManager — usado pelas abas.</summary>
    public void PlaySfx(AudioClip clip) => AudioManager.Instance?.PlaySE(clip);

    // ---------------- Animação ----------------

    private void PlayAnimation(bool opening)
    {
        if (animRoutine != null) StopCoroutine(animRoutine);
        animRoutine = StartCoroutine(AnimateRoutine(opening));
    }

    private IEnumerator AnimateRoutine(bool opening)
    {
        float from = opening ? closedScale : 1f;
        float to = opening ? 1f : closedScale;
        float fromAlpha = opening ? 0f : 1f;
        float toAlpha = opening ? 1f : 0f;

        float t = 0f;
        float duration = Mathf.Max(0.01f, animDuration);

        while (t < duration)
        {
            t += Time.unscaledDeltaTime;
            float p = Mathf.Clamp01(t / duration);
            float eased = 1f - Mathf.Pow(1f - p, 3f);

            if (animatedRoot != null) animatedRoot.localScale = Vector3.one * Mathf.Lerp(from, to, eased);
            if (canvasGroup != null) canvasGroup.alpha = Mathf.Lerp(fromAlpha, toAlpha, eased);

            yield return null;
        }

        if (animatedRoot != null) animatedRoot.localScale = Vector3.one * to;
        if (canvasGroup != null) canvasGroup.alpha = toAlpha;

        if (!opening)
        {
            if (panelRoot != null) panelRoot.SetActive(false);

            GamePauseUtil.Resume();
            AudioManager.Instance?.SetBgmMuffled(false);
        }
    }
}

/// <summary>
/// Adapta um <see cref="IPauseMenuSection"/> para <see cref="ISecondaryMenuTab"/>,
/// permitindo que secções existentes do Menu de Pausa (AreaSectionUI,
/// DiarySectionUI, etc.) sejam usadas directamente no SecondaryMenuController
/// sem precisar de alterar os seus scripts.
/// </summary>
internal sealed class PauseSectionAdapter : ISecondaryMenuTab
{
    private readonly IPauseMenuSection _section;

    public PauseSectionAdapter(IPauseMenuSection section) => _section = section;

    public string TabName => _section.SectionName;
    public UnityEngine.GameObject Root => _section.Root;
    public void Refresh() => _section.Refresh();
    public void OnHide() => _section.OnHide();
}
